import React, { useState, useEffect } from "react";
import { useLocation, Redirect } from "react-router";
import axios from "../axios";
import MovieCard from "./MovieCard";
import { AllMoviesStore } from "../store/AllMoviesStore";

var page = 1;

function ALLMovies() {
  // const location = useLocation();
  // const { fetchUrl, title, mediaType } = location.state;
  const fetchUrl = AllMoviesStore.useState((s) => s.fetchUrl);
  const title = AllMoviesStore.useState((s) => s.title);
  const mediaType = AllMoviesStore.useState((s) => s.mediaType);
  const [movies, setMovies] = useState([]);
  // first load
  useEffect(() => {
    async function fetchData() {
      const res = await axios.get(fetchUrl);
      setMovies(res.data.results);
    }
    fetchData();
  }, []);
  // load more handler
  const loadMoreHandler = async () => {
    page++;
    const res = await axios.get(`${fetchUrl}&page=${page}`);
    setMovies([...movies, ...res.data.results]);
  };

  return (
    <div className="all_movies_holder">
      <h1 className="title">{title}</h1>
      <div className="inner_all_movies_holder">
        {movies.map((movie, key) => {
          return <MovieCard movie={movie} mediaType={mediaType} key={key} />;
        })}
      </div>
      <div className="load_more_holder">
        <button className="more_button_2" onClick={loadMoreHandler}>
          more
        </button>
      </div>
    </div>
  );
}

export default ALLMovies;
