import axios from "../axios";
import React, { useState, useEffect } from "react";
import MovieCard from "./MovieCard";
import Slider from "react-slick";
import { useMediaQuery } from "react-responsive";
import { Link } from "react-router-dom";
import { AllMoviesStore } from "../store/AllMoviesStore";

function Row({ title, fetchUrl, isLarge, setIsLoading, isFirst, mediaType }) {
  const [movies, setMovies] = useState([]);
  const isBigScreen = useMediaQuery({ query: "(min-width: 790px)" });
  // here i fetch url to get the movie on load
  useEffect(() => {
    async function fetchData() {
      setIsLoading(true);
      const res = await axios.get(fetchUrl);
      setMovies(res.data.results);
      setIsLoading(false);
    }
    fetchData();
  }, [fetchUrl]);
  const settings = {
    dots: false,
    speed: 500,
    slidesToShow: isLarge ? 2 : 4,
    slidesToScroll: isLarge ? 2 : 4,
    initialSlide: 0,
    variableWidth: true,
    adaptiveHeight: true,
    infinite: false,
    focusOnSelect: true,
    arrows: true,
    responsive: [
      {
        breakpoint: 460,
        settings: {
          slidesToShow: 1,
          slidesToScroll: 1,
        },
      },
    ],
  };

  return (
    <div className="row" id={isFirst ? "firstRow" : "ntgh"}>
      <h2
        onClick={(e) =>
          AllMoviesStore.update((s) => {
            s.fetchUrl = fetchUrl;
            s.title = title;
            s.mediaType = mediaType;
          })
        }
      >
        <Link
          className="title"
          to={{
            pathname: "/all-movies",
          }}
        >
          {title} <span>&#8594;</span>
        </Link>
      </h2>

      {isBigScreen ? (
        <Slider {...settings}>
          {movies.map((movie, key) => {
            return (
              <MovieCard
                movie={movie}
                isLarge={isLarge}
                mediaType={mediaType}
                key={key}
              />
            );
          })}
          <Link
            className="more_button"
            to={{
              pathname: "/all-movies",
              state: { fetchUrl, title, mediaType },
            }}
          >
            more
          </Link>
        </Slider>
      ) : (
        <div className="row__posters">
          {movies.map((movie, key) => {
            return (
              <MovieCard
                movie={movie}
                isLarge={isLarge}
                mediaType={mediaType}
                key={key}
              />
            );
          })}
          <Link
            className="more_button"
            to={{
              pathname: "/all-movies",
              state: { fetchUrl, title, mediaType },
            }}
          >
            more
          </Link>
        </div>
      )}
    </div>
  );
}

export default Row;
